external_knowledge:
- 'digital gold' refers to 'crypto_name';
- 'total treasure lost in the form of fees' refers to the sum of 'fee_amount';
- 'transactions' refers to trades involving a specific cryptocurrency;
- 'crypto_id = 1' refers to a specific cryptocurrency.

sql:
SELECT trade_type
FROM trades
WHERE trade_id = 1;

SELECT COUNT(*)
FROM trades
WHERE user_id = (SELECT user_id FROM users WHERE username = 'John Smith');

SELECT t.trade_profit, t.trade_type
FROM trades t
INNER JOIN users u ON t.user_id = u.user_id;

external_knowledge:
- "seafarers" refers to active users who have made trades;
- "vast ocean of cryptocurrencies" refers to the cryptocurrency market;
- "landed their treasures" refers to completing trades;
- "more than 100 gold coins" means the minimum trade price is greater than 100;
- "since the dawn of this year" refers to trades completed after January 1, 2023;
- "details of their voyages" points to trade details like trade ID, total trade value, and fees;
- "size of their ships" refers to the type of account (standard, premium);
- "treasures they've amassed" refers to the user's net worth;
- "toll the journey has taken on their resources" refers to total fees incurred by the trade.

